// 1. 定義 item
const item = $input.item.json;
const rawString = item.text || item.output || item.content || "";

// 2. 解析 JSON
let jsonData = { content: "無內容", metadata: {} };
try {
  const cleanString = rawString.replace(/```json/g, "").replace(/```/g, "").trim();
  if (cleanString) jsonData = JSON.parse(cleanString);
} catch (e) { console.log("解析失敗"); }

// 3. 處理 Metadata
let metaObj = {};
try {
  metaObj = (typeof jsonData.metadata === 'string') ? JSON.parse(jsonData.metadata) : (jsonData.metadata || {});
} catch (e) { metaObj = {}; }
if (!Array.isArray(metaObj.options)) metaObj.options = [];

// 4. 組合「給 AI 算向量用的」長文字 (包含答案解析)
const fullTextForEmbedding = `
題目：${jsonData.content}
選項：${metaObj.options.join(", ")}
解析：${metaObj.explanation || "無"}
`.trim();

return {
  json: {
    // 變數 A：給 Supabase 算向量用的 (長)
    pageContent: fullTextForEmbedding,

    // 變數 B：你要存進 content 欄位的 (短，只有題目)
    content: jsonData.content,

    // 變數 C：你要存進 metadata 欄位的 (乾淨的物件)
    metadata: metaObj
  },
  // 🔥 強制移除檔案，強迫 Supabase 讀變數
  binary: undefined
};

