// 1. 靈活提取文字內容 (優先順序：目前輸入 > 原始 Webhook)
const event = $json.body?.events?.[0] || $('Webhook').first().json.body.events[0];
const text = (event?.message?.text || "").replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();

// 2. 提取來源 ID (優先順序：目前輸入 > 原始 Webhook)
const groupId = event?.source?.groupId || $('Webhook').first().json.body.events[0].source.groupId;

const regex = /(?:@\s+)?\/open\s+(\d+)(?:\s+(\d+))?/;
const match = text.match(regex);

let qid = null;
let duration = 3; 

if (match) {
  qid = match[1]; 
  if (match[2]) {
    duration = parseInt(match[2]);
  }
}

return {
  qid: qid,
  duration: duration,
  groupId: groupId,
  valid: !!qid, // 增加一個標記，方便後續 If 節點判斷是否解析成功
  debug_raw_text: text 
};

// 取得 Supabase 查到的所有資料
const allStudents = items.map(item => item.json);

// 分組：答對的放一邊，答錯的放一邊
const correctList = allStudents.filter(s => s.is_correct === true);
const wrongList = allStudents.filter(s => s.is_correct === false);

// 定義一個小函式來整理名單 (格式：1. 王小明 (12345) [選A])
const formatList = (list) => {
    if (list.length === 0) return "   (無)";
    return list.map((s, i) => `${i + 1}. ${s.display_name} (${s.student_id}) [選${s.selected_option}]`).join('\n');
};

// 組合最終訊息
const message = `📊 第 ${allStudents[0]?.question_id || '?'} 題完整統計

✅ 答對人數：${correctList.length} 人
----------------
${formatList(correctList)}

❌ 答錯人數：${wrongList.length} 人
----------------
${formatList(wrongList)}`;

// 輸出
return [{
    json: {
        reply_text: message
    }
}];

// 1. 抓取文字 (混合讀取邏輯)
// $input.first() 等同於介面上的 $json (讀取當前節點輸入)
// $('Webhook').first() 等同於讀取原始資料
const currentText = $input.first()?.json?.body?.events?.[0]?.message?.text;
const webhookText = $('Webhook').first()?.json?.body?.events?.[0]?.message?.text;

// 邏輯：優先使用當前輸入(AI)，如果是空的，就回頭用 Webhook(真人)，再沒有就給空字串
const text = currentText || webhookText || "";

// 2. 正則表達式 (解析指令)
// 這裡維持你原本的邏輯，抓取 /open 題號 時間 群組
const regex = /\/open\s+(\d+)(?:\s+(\d+))?(?:\s+(.+))?/;
const match = text.match(regex);

if (!match) {
  return { valid: false };
}

return {
  valid: true,
  qid: match[1],                      // 題號
  duration: parseInt(match[2] || 3),  // 時間 (沒填預設 3 分鐘)
  target_group: match[3] || null      // 群組名稱 (沒填就是 null)
};

