    if (list.length === 0) return "   (無)";
    return list.map((s, i) => `${i + 1}. ${s.display_name} (${s.student_id}) [選${s.selected_option}]`).join('\n');
};

// 組合最終訊息
const message = `📊 第 ${allStudents[0]?.question_id || '?'} 題完整統計

✅ 答對人數：${correctList.length} 人
----------------
${formatList(correctList)}

❌ 答錯人數：${wrongList.length} 人
----------------
${formatList(wrongList)}`;

// 輸出
return [{
    json: {
        reply_text: message
    }
}];

// 取得 "Parse Command1" 設定的時間
