} else if (parseData.target_group_name && !groupData.group_id) {
    // 這裡維持原樣即可
}

// 3. 準備文案
const opts = q.metadata?.options || ["(A)", "(B)", "(C)", "(D)"]; // 加入 ?. 確保安全
const duration = parseData.duration || 3;

const speedText = `⚡️ 加分模式啟動！ (限時 ${duration} 分鐘) ⚡️
=======================
🥇 冠軍獨得 +3 分
🥈 第 2~5 名 +2 分
=======================

[題目]
${q.content}

[選項]
(A) ${opts[0]}
(B) ${opts[1]}
(C) ${opts[2]}
(D) ${opts[3]}

👇 請點擊下方按鈕搶分！ 👇`;

// 4. 輸出
return {
  text: speedText,
  qid: q.id, 
  group_id: finalGroupId 
};

