parameters.jsCode:
// ==========================================
// 1. 取得環境資訊
// ==========================================
// 回頭去問 "找id" 節點，現在這個群組是什麼模式？
const groupInfo = $('找id').first().json;
const gameMode = groupInfo.game_mode || 'normal'; // 預設為普通模式

// ==========================================
// 2. 計算排名
// ==========================================
let historyItems = $input.all();
if (historyItems.length === 1 && Object.keys(historyItems[0].json).length === 0) {
    historyItems = [];
}
const myRank = historyItems.length + 1;

// ==========================================
// 3. 計算分數 (🔥 修改重點：基礎分改為 10)
// ==========================================
let score = 10; // 預設答對就是 10 分 (基礎分)
let bonusMsg = "✅ 答對了！";

if (gameMode === 'speed') {
  // --- ⚡️ 競速模式 (基礎分 + 加成) ---
  if (myRank === 1) {
    score = 13; // 基礎 10 + 加成 3
    bonusMsg = "⚡️ 首殺！速度加成 +3 分！";
  } else if (myRank <= 5) {
    score = 12; // 基礎 10 + 加成 2
    bonusMsg = `🚀 第 ${myRank} 名！速度加成 +2 分！`;
  } else {
    // 第 6 名以後，雖然沒搶到前段班，還是有基礎 10 分
    score = 10;
    bonusMsg = "✅ 答對了！(可惜沒搶到前 5 名)";
  }
} else {
  // --- 🐢 普通模式 ---
  score = 10; // 普通模式直接拿基礎 10 分
  bonusMsg = "✅ 答對了！";
}

// ==========================================
// 4. 抓取資料 (維持不動)
// ==========================================
let qid = 0;
let opt = "Error";
let userId = "Error";
let rawData = "無資料"; 

try {
  const event = $('Webhook').first().json.body.events[0];
  userId = event.source.userId;

  if (event.type === 'postback') {
      rawData = event.postback.data; 
      const qidMatch = rawData.match(/qid=(\d+)/);
      if (qidMatch) qid = parseInt(qidMatch[1]);

      const optMatch = rawData.match(/opt=([A-Za-z0-9]+)/);
      if (optMatch) opt = optMatch[1];
  }
} catch (e) {
  try {
      const parseData = $('解析搶答文字').first().json;
      if (parseData.qid) qid = parseData.qid;
      if (parseData.opt) opt = parseData.opt;
  } catch (e2) {}
}

// ==========================================
// 5. 輸出
// ==========================================
return {
  json: {
    score: score,
    rank: myRank,
    bonus_msg: bonusMsg,
    game_mode: gameMode, 
    group_id: $('Webhook').first().json.body.events[0].source.groupId, // 記得要帶上 group_id

    // 寫入資料庫欄位
    user_id: userId,
    question_id: qid,
    selected_option: opt,
    is_correct: true
  }
};

// 1. 取得前面查到的所有班級資料
const groups = $input.all().map(item => item.json);

// 2. 取得原始輸入文字
const webhookNode = $('Webhook').first(); 
const text = webhookNode.json.body.events[0]?.message?.text || "";

// 🔥 修正點：改進 Regex 以捕獲第二個參數 (時間)
// (\d+) 抓題號，(?:\s+(\d+))? 選擇性抓取空白後的數字當時間
const match = text.match(/\/open\s+(\d+)(?:\s+(\d+))?/);

// 如果抓得到題號數字就用，抓不到就預設第 1 題
const qid = match ? match[1] : '1'; 

// 🔥 修正點：從 match[2] 取得時間，如果沒輸入則維持預設 3 分鐘
const duration = (match && match[2]) ? match[2] : '3'; 

// 3. 製作按鈕陣列
const buttons = groups.map(g => {
  // 優先抓取關聯後的名稱，防呆機制
  const groupName = (g.groups && g.groups.group_name) ? g.groups.group_name : (g.group_name || "未命名群組");

  return {
    "type": "button",
    "style": "secondary",
    "height": "sm",
    "action": {
      "type": "message",
      "label": groupName,
      // 現在這裡的 ${duration} 會根據你輸入的指令動態改變了
      "text": `/open ${qid} ${duration} ${groupName}` 
    },
    "margin": "sm"
  };
});

// 4. 組裝 Flex Bubble
const flexPayload = {
  "type": "bubble",
  "body": {
    "type": "box",
    "layout": "vertical",
    "contents": [
      {
        "type": "text",
        "text": "📋 請選擇要開放的班級",
        "weight": "bold",
        "size": "lg"
      },
      {
        "type": "text",
        "text": `您名下有多個班級，請選擇本次要對哪一班開放「第 ${qid} 題」，限時 ${duration} 分鐘：`,
        "size": "xs",
        "color": "#aaaaaa",
        "wrap": true,
        "margin": "md"
      },
      {
        "type": "separator",
        "margin": "md"
      },
      ...buttons
    ]
  }
};

return {
  flex_json: flexPayload
};

