  "color": "#1DB446",
  "action": {
    "type": "message",
    "label": "🌏 生涯總戰績",
    "text": "/me_query total"
  }
};

// 4. 組合選單內容 (改用動態陣列 push 的方式)
const contents = [
  {
    "type": "text",
    "text": "📊 請選擇查詢範圍",
    "weight": "bold",
    "size": "lg",
    "align": "center"
  },
  {
