  }
};

return { flex_json: flexPayload };

// 1. 取得資料
const items = $input.all().map(item => item.json);

// 2. 👻 處理「沒有戰績」的情況 (防呆)
// 如果陣列是空的，或是第一筆資料是空的物件
if (items.length === 0 || Object.keys(items[0]).length === 0) {
  const replyToken = $('Webhook').first().json.body.events[0].replyToken;
  return {
    flex_json: {
      "type": "bubble",
      "body": {
        "type": "box",
        "layout": "vertical",
        "contents": [
          {
            "type": "text",
            "text": "尚無答題紀錄",
            "weight": "bold",
            "color": "#ff5555",
            "size": "md"
          },
          {
            "type": "text",
            "text": "👻",
            "size": "5xl",
            "align": "center",
            "margin": "md"
          },
          {
            "type": "text",
            "text": "目前沒有您的戰績紀錄喔！\n快去參加考試吧！",
            "wrap": true,
            "color": "#666666",
            "margin": "md",
            "align": "center"
          }
        ]
      }
    }
  };
}

// 3. 判斷模式 (生涯/單班)
const event = $('Webhook').first().json.body.events[0];
const text = event.message.text || "";
const sourceType = event.source.type;
const isTotalMode = (sourceType === 'user' && text.trim() === '/me') || text.includes('total');

// 4. 計算數據
let totalScore = 0;
let correctCount = 0;
let totalQuestions = 0; // 總答題數
let rankDisplay = "生涯模式";
let title = "🌏 生涯總戰績";

if (isTotalMode) {
  // --- 🌏 生涯模式：累加所有班級數據 ---
  totalScore = items.reduce((sum, i) => sum + (i.total_score || 0), 0);
  correctCount = items.reduce((sum, i) => sum + (i.correct_count || 0), 0);
  totalQuestions = items.reduce((sum, i) => sum + (i.total_count || 0), 0);
  rankDisplay = "跨班累計";
  title = "🌏 生涯總戰績";
} else {
  // --- 🏫 單班模式 ---
  const data = items[0] || {};
  totalScore = data.total_score || 0;
  correctCount = data.correct_count || 0;
  totalQuestions = data.total_count || 0;
  rankDisplay = data.rank_no ? `第 ${data.rank_no} 名` : "未上榜";

  if (text.includes('group')) {
    const groupName = text.split(' ').slice(2).join(' ') || "特定班級";
    title = `🏫 ${groupName} 戰績`;
  } else {
    title = "🏫 本班戰績查詢";
  }
}

// 5. 衍生計算 (答錯次數 & 正確率)
const wrongCount = totalQuestions - correctCount;
// 避免除以 0 (如果總題數是 0，正確率就是 0)
const accuracy = totalQuestions > 0 ? Math.round((correctCount / totalQuestions) * 100) : 0;

// 6. 定義等級與顏色
let rankTitle = "🌱 新手村";
let rankColor = "#888888";
if (totalScore >= 100) { rankTitle = "🥉 銅牌學徒"; rankColor = "#cd7f32"; }
if (totalScore >= 500) { rankTitle = "🥈 銀牌高手"; rankColor = "#c0c0c0"; }
if (totalScore >= 1000) { rankTitle = "🥇 金牌大師"; rankColor = "#ffd700"; }
if (totalScore >= 2000) { rankTitle = "👑 傳說戰神"; rankColor = "#E60012"; }

// 7. 隱碼 User ID
const userId = event.source.userId;
const hiddenUserId = userId.substring(0, 8) + "...";

// 8. 製作 Flex Message
const flexPayload = {
  "type": "bubble",
  "size": "giga",
  "body": {
    "type": "box",
    "layout": "vertical",
    "contents": [
      {
        "type": "text",
        "text": title,
        "weight": "bold",
        "color": "#1DB446",
        "size": "sm"
      },
      {
        "type": "text",
        "text": rankTitle,
        "weight": "bold",
        "size": "xxl",
        "margin": "md",
        "color": rankColor
      },
      { "type": "separator", "margin": "lg" },
      {
        "type": "box",
        "layout": "vertical",
        "margin": "lg",
        "contents": [
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": isTotalMode ? "統計模式" : "目前排名", "size": "sm", "color": "#555555" },
              { "type": "text", "text": rankDisplay, "size": "xl", "color": "#E60012", "align": "end", "weight": "bold" }
            ]
          },
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "🎯 正確率", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${accuracy}%`, "size": "sm", "color": "#111111", "align": "end", "weight": "bold" }
            ]
          },
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "✅ 答對題數", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${correctCount} 題`, "size": "sm", "color": "#111111", "align": "end", "weight": "bold" }
            ]
          },
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "❌ 答錯次數", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${wrongCount} 題`, "size": "sm", "color": "#111111", "align": "end", "weight": "bold" }
            ]
          },
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "🏆 總積分", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${totalScore} 分`, "size": "sm", "color": "#E60012", "align": "end", "weight": "bold" }
            ]
          }
        ]
      },
      { "type": "separator", "margin": "lg" },
