// ==========================================
// 👇 以下是原本的正常邏輯 (有資料才會跑這裡)
// ==========================================

// 2. 回頭看 Webhook：使用者當初到底傳了什麼？
const event = $('Webhook').first().json.body.events[0];
const text = event.message.text || "";       
const sourceType = event.source.type;        

// 3. 判斷是否為「生涯總分模式」 (Total Mode)
const isTotalMode = (sourceType === 'user' && text.trim() === '/me') || text.includes('total');

// 4. 初始化變數
let totalScore = 0;
let correctCount = 0;
let rankDisplay = "生涯模式";
let title = "🌏 生涯總戰績";

if (isTotalMode) {
  // 🌏 生涯模式
  totalScore = items.reduce((sum, item) => sum + (item.total_score || 0), 0);
  correctCount = items.reduce((sum, item) => sum + (item.correct_count || 0), 0);
  rankDisplay = "跨班累計";
  title = "🌏 生涯總戰績";

} else {
  // 🏫 單班模式
  const data = items.length > 0 ? items[0] : {}; 

  totalScore = data.total_score || 0;
  correctCount = data.correct_count || 0;

  rankDisplay = data.rank_no ? `第 ${data.rank_no} 名` : "尚未上榜";

  if (text.includes('group')) {
    const groupName = text.split(' ').slice(2).join(' ') || "特定班級";
    title = `🏫 ${groupName} 戰績`;
  } else {
    title = "🏫 本班戰績查詢";
  }
}

// 5. 定義等級稱號
let rankTitle = "🌱 新手村";
let rankColor = "#888888";
if (totalScore >= 100) { rankTitle = "🥉 銅牌學徒"; rankColor = "#cd7f32"; }
if (totalScore >= 500) { rankTitle = "🥈 銀牌高手"; rankColor = "#c0c0c0"; }
if (totalScore >= 1000) { rankTitle = "🥇 金牌大師"; rankColor = "#ffd700"; }
if (totalScore >= 2000) { rankTitle = "👑 傳說戰神"; rankColor = "#E60012"; }

// 6. 抓取 User ID
const userId = event.source.userId;
const hiddenUserId = userId.substring(0, 8) + "...";

// 7. 製作 Flex Message 卡片 (正常版)
const flexPayload = {
  "type": "bubble",
  "size": "giga",
  "body": {
    "type": "box",
    "layout": "vertical",
    "contents": [
      {
        "type": "text",
        "text": title,
        "weight": "bold",
        "color": "#1DB446",
        "size": "sm"
      },
      {
        "type": "text",
        "text": rankTitle,
        "weight": "bold",
        "size": "xxl",
        "margin": "md",
        "color": rankColor
      },
      { "type": "separator", "margin": "lg" },
      {
        "type": "box",
        "layout": "vertical",
        "margin": "lg",
        "contents": [
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": isTotalMode ? "統計模式" : "目前排名", "size": "sm", "color": "#555555" },
              { "type": "text", "text": rankDisplay, "size": "xl", "color": "#E60012", "align": "end", "weight": "bold" }
            ]
          },
          {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "總積分", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${totalScore} 分`, "size": "sm", "color": "#111111", "align": "end", "weight": "bold" }
            ]
          },
           {
            "type": "box",
            "layout": "horizontal",
            "contents": [
              { "type": "text", "text": "答對題數", "size": "sm", "color": "#555555" },
              { "type": "text", "text": `${correctCount} 題`, "size": "sm", "color": "#111111", "align": "end", "weight": "bold" }
            ]
          }
        ]
      },
      { "type": "separator", "margin": "lg" },
      {
        "type": "box",
        "layout": "horizontal",
        "margin": "md",
        "contents": [
          { "type": "text", "text": "User ID:", "size": "xxs", "color": "#aaaaaa" },
          { "type": "text", "text": hiddenUserId, "size": "xxs", "color": "#aaaaaa", "align": "end" }
        ]
      }
    ]
  }
};

return { flex_json: flexPayload };

// 1. 抓取指令文字
const text = $('Webhook').first().json.body.events[0].message.text || "";

// 2. 定義 Regex (強烈建議用這個，防呆又防 Tag)
// 邏輯解說：
// .* -> 允許前面有雜訊 (例如 @機器人)
// \/me_query   -> 鎖定指令
// \s+          -> 空白
// (total|group)-> 第1組：抓取模式 (一定要是 total 或 group)
// (?:\s+(.+))? -> 第2組 (選填)：抓取後面的班級名稱
const regex = /.*\/me_query\s+(total|group)(?:\s+(.+))?/;

const match = text.match(regex);

// 3. 判斷是否符合
if (!match) return { valid: false };

// 4. 回傳結果
return {
  valid: true,
  query_type: match[1],  // 這裡會精準抓到 'group' 或 'total'

  // 這裡會抓到 '0001' (如果有填的話)，沒填就預設 '本班級'
  group_name: match[2] ? match[2].trim() : "本班級", 

  group_id: null,
  user_id: $('Webhook').first().json.body.events[0].source.userId
};

// 1. 抓取文字 (優先看當前傳入的 $json，再看 Webhook 原始資料)
const webhookNode = $('Webhook').first(); 
const currentText = $json.body?.events?.[0]?.message?.text;
const backupText = webhookNode.json.body.events?.[0]?.message?.text || "";

const rawText = currentText || backupText;

// 2. 清洗資料
const cleanText = rawText.replace(/　/g, ' ').replace(/\r?\n/g, ' ').trim();

// 3. 切分指令
const parts = cleanText.split(' ').filter(token => token !== '');

// 4. 解析
if (parts[0] !== '/close') {
  return { valid: false };
}

// 判斷有沒有帶班級參數
let targetGroup = null;
if (parts.length >= 2) {
  // 把第二個參數之後的所有東西接起來當名稱 (防止有空格)
  targetGroup = parts.slice(1).join(' ');
}

return {
  valid: true,
  target_group_name: targetGroup, // 如果是 null，代表老師只打了 /close

  // 🔽 修正點：統一使用 .first() 或當前 $json，徹底解決鎖死問題
  current_group_id: $json.body?.events?.[0]?.source?.groupId || 
                    webhookNode.json.body.events?.[0]?.source?.groupId || 
                    null
};

// 1. 取得前面查到的所有班級資料
const groups = $input.all().map(item => item.json);

// 2. 製作按鈕陣列
const buttons = groups.map(g => {
  // 取得群組名稱 (優先抓 Join 進來的，沒有就用原本的)
  const groupName = (g.groups && g.groups.group_name) ? g.groups.group_name : (g.group_name || "未命名群組");

  return {
    "type": "button",
    "style": "secondary", // 關閉操作建議用灰色 (secondary)
    "height": "sm",
    "action": {
      "type": "message",
      "label": groupName, // 按鈕上顯示的字
      // 🔽 修改重點：按下去送出 "/close 班級名稱" 🔽
      "text": `/close ${groupName}` 
    },
    "margin": "sm"
  };
});

// 3. 組裝成完整的 Flex Bubble 結構
const flexPayload = {
  "type": "bubble",
  "body": {
    "type": "box",
    "layout": "vertical",
    "contents": [
      {
        "type": "text",
        "text": "🛑 請選擇要關閉的班級", // 標題：清楚告知這是關閉操作
        "weight": "bold",
        "size": "lg",
        "color": "#e04f5f" // 標題用一點紅色警示
      },
      {
        "type": "text",
        "text": "您名下有多個班級，請選擇要結束哪一班的考試：",
        "size": "xs",
        "color": "#aaaaaa",
        "wrap": true,
        "margin": "md"
      },
      {
        "type": "separator",
        "margin": "md"
      },
      // 動態生成的按鈕
      ...buttons
    ]
  }
};

return {
  flex_json: flexPayload
};

const text = $('Webhook').first().json.body.events[0].message.text || "";

const match = text.match(/^\/rank(?:\s+(.+))?$/);

let groupName = null;
let mode = "all"; 

if (match && match[1]) {
    groupName = match[1].trim();
    mode = "group"; 
}

return {
    json: {
        mode: mode,
        group_query: groupName
    }
};

const rows = items.map(item => item.json);
const queryName = $('RANK4').first()?.json?.group_query;
const isInvalid = rows.length === 0 || (rows.length === 1 && !rows[0].display_name);

if (isInvalid) {
  const targetName = queryName || '全校';
  return [{ json: { text: `🏆 找不到「${targetName}」的答題紀錄喔！` } }];
}

let scopeTitle = queryName ? `[${queryName}] 班級排行` : "全校總排行";


let msg = `🏆 **${scopeTitle} (Top 10)**\n====================\n`;


rows.forEach((row, index) => {
  let rankDisplay = "";


  const count = row.total_count || 0; 


  if (index === 0) {
    rankDisplay = `🥇 [冠軍] ${row.display_name}\n      └── ⚔️ 答對 ${count} 題 🔥`;
  } else if (index === 1) {
    rankDisplay = `🥈 [亞軍] ${row.display_name} : ${count} 題`;
  } else if (index === 2) {
    rankDisplay = `🥉 [季軍] ${row.display_name} : ${count} 題`;
  } else {
    rankDisplay = `No.${index + 1}  ${row.display_name} : ${count} 題`;
  }

  msg += `${rankDisplay}\n`;
});


msg += "\n💪 各位同學繼續加油！";


return [{ json: { text: msg } }];

// 1. 取得題目最後發送時間 (從 "登記2" 節點來的)
const sentTimeStr = $json.last_sent_at;

// 2. 取得現在時間 (學生答題當下)
const answerTime = new Date();

// 3. 計算秒數
let reactionTime = 0;

if (sentTimeStr) {
  const sentTime = new Date(sentTimeStr);
  // 相減是毫秒，除以 1000 變秒
  const diff = (answerTime - sentTime) / 1000;

  // 防呆：如果是負數(時區問題)或大於1小時(隔太久)，就記為 0 或 null
  if (diff > 0 && diff < 3600) {
    reactionTime = parseFloat(diff.toFixed(1)); // 只留一位小數
  }
}

// 4. 把算好的時間合併回原本的資料，往下傳
return {
  json: {
    ...$json, // 保留原本的資料 (qid, option, metadata...)
    reaction_time: reactionTime
  }
};

const { action, qid, target_user_id, target_name, group_name } = query;

if (action === 'private_quiz') {
  return `已確認參數：動作 私訊抽考, 學生 ${target_name}, 題號 ${qid}。`;
} else if (action === 'close') {
  return `已確認參數：動作 關閉測驗, 班級 ${group_name}。`;
} else {
  return `已確認參數：動作 開啟測驗... (略)`;
}

